
const tracks = [
    { id: 'audio-drake', title: 'DRAKE.MP3',  label: '<i class="fa-solid fa-music"></i>' },
    { id: 'audio-jb',    title: 'JB.MP3',     label: '<i class="fa-solid fa-compact-disc"></i>' },
  ];
let currentTrack = 0;
let isPlaying = false;

const PLAY_ICON  = `<i class="fa-solid fa-play"></i>`;
const PAUSE_ICON = `<i class="fa-solid fa-pause"></i>`;

const playBtn  = document.getElementById('play-btn');
const prevBtn  = document.getElementById('prev-btn');
const nextBtn  = document.getElementById('next-btn');
const playerTitle = document.getElementById('player-title');
const playerArt   = document.getElementById('player-art');
const progressFill = document.getElementById('player-progress-fill');

function getAudio(idx) {
  return document.getElementById(tracks[idx].id);
}
function loadTrack(idx, autoPlay) {
  tracks.forEach((t, i) => {
    const a = getAudio(i);
    a.pause();
    a.currentTime = 0;
  });
  currentTrack = idx;
  playerTitle.textContent = tracks[idx].title;
  playerArt.innerHTML   = tracks[idx].label;
  
  if (autoPlay) {
    getAudio(idx).play().catch(()=>{});
    isPlaying = true;
    playBtn.innerHTML = PAUSE_ICON;
    playerArt.classList.add('playing');
  } else {
    isPlaying = false;
    playBtn.innerHTML = PLAY_ICON;
    playerArt.classList.remove('playing');
  }
}

playBtn.addEventListener('click', () => {
  const audio = getAudio(currentTrack);
  if (isPlaying) {
    audio.pause();
    isPlaying = false;
    playBtn.innerHTML = PLAY_ICON;
    playerArt.classList.remove('playing');
  } else {
    audio.play().catch(()=>{});
    isPlaying = true;
    playBtn.innerHTML = PAUSE_ICON;
    playerArt.classList.add('playing');
  }
});

prevBtn.addEventListener('click', () => {
  loadTrack((currentTrack - 1 + tracks.length) % tracks.length, isPlaying);
});
nextBtn.addEventListener('click', () => {
  loadTrack((currentTrack + 1) % tracks.length, isPlaying);
});

tracks.forEach((t, i) => {
  getAudio(i).addEventListener('ended', () => {
    loadTrack((i + 1) % tracks.length, true);
  });
});

setInterval(() => {
  const audio = getAudio(currentTrack);
  if (audio.duration) {
    progressFill.style.width = (audio.currentTime / audio.duration * 100) + '%';
  }
}, 500);

document.addEventListener('click', () => {
  if (isPlaying) getAudio(currentTrack).play().catch(()=>{});
}, { once: true });

