const roadsConfig = [
  {x:0, z:0, w:16, l:500, rot:0},
  {x:0, z:0, w:500, l:16, rot:Math.PI/2},
  {x:0, z:60, w:500, l:12, rot:Math.PI/2},
  {x:0, z:-60, w:500, l:12, rot:Math.PI/2}
];
function checkRoadCollision(x,z,sizeW,sizeD){
  const margin=4;
  for(let r of roadsConfig){
    if(r.rot===0){
      if(x+sizeW/2>r.x-r.w/2-margin && x-sizeW/2<r.x+r.w/2+margin) return true;
    } else {
      if(z+sizeD/2>r.z-r.l/2-margin && z-sizeD/2<r.z+r.l/2+margin) return true;
    }
  }
  return false;
}
roadsConfig.forEach(r=>{
  const road = new THREE.Mesh(new THREE.PlaneGeometry(r.w,r.l), new THREE.MeshLambertMaterial({color:0x091122}));
  road.rotation.x=-Math.PI/2; road.rotation.z=r.rot;
  road.position.set(r.x,0.05,r.z);
  scene.add(road);
  let loopLen = r.rot===0?r.l:r.w;
  for(let i=-loopLen/2+5; i<loopLen/2; i+=10){
    const mark = new THREE.Mesh(new THREE.PlaneGeometry(0.4,4), new THREE.MeshBasicMaterial({color:0x22385e}));
    mark.rotation.x=-Math.PI/2; mark.rotation.z=r.rot;
    mark.position.set(r.rot===0?r.x:r.x+i, 0.06, r.rot===0?r.z+i:r.z);
    scene.add(mark);
  }
});
roadsConfig.forEach(r=>{
  let loopLen=r.rot===0?r.l:r.w;
  for(let i=-loopLen/2+20; i<loopLen/2; i+=45){
    if(Math.abs(i)<15&&Math.abs(r.x)<15&&Math.abs(r.z)<15) continue;
    [-(r.w/2+1.5),(r.w/2+1.5)].forEach(off=>{
      let lx=r.rot===0?r.x+off:r.x+i;
      let lz=r.rot===0?r.z+i:r.z+off;
      const pole = new THREE.Mesh(new THREE.CylinderGeometry(0.15,0.15,8,6), new THREE.MeshLambertMaterial({color:0x1e293b}));
      pole.position.set(lx,4,lz);
      scene.add(pole);
      const lamp = new THREE.Mesh(new THREE.SphereGeometry(0.4,8,8), new THREE.MeshBasicMaterial({color:0xfef08a}));
      lamp.position.set(lx,8.2,lz);
      scene.add(lamp);
      const ll = new THREE.PointLight(0xeab308,0.8,22);
      ll.position.set(lx,8,lz);
      scene.add(ll);
    });
  }
});

