function makeBuilding(x,z,w,h,d,palette,portfolioIdx=-1,isLandmark=false){
  if(checkRoadCollision(x,z,w,d)) return null;
  const group=new THREE.Group();
  const geo=new THREE.BoxGeometry(w,h,d);
  const mat=new THREE.MeshLambertMaterial({color:palette.base,emissive:palette.emissive,emissiveIntensity:1.0});
  const mesh=new THREE.Mesh(geo,mat);
  mesh.position.y=h/2;
  group.add(mesh);
  if(h>40&&isLandmark){
    const topW=w*0.65,topH=h*0.3,topD=d*0.65;
    const topMesh=new THREE.Mesh(new THREE.BoxGeometry(topW,topH,topD),mat.clone());
    topMesh.position.y=h+topH/2;
    group.add(topMesh);
    const ant=new THREE.Mesh(new THREE.CylinderGeometry(0.1,0.1,h*0.2,6),new THREE.MeshBasicMaterial({color:0x475569}));
    ant.position.y=h+topH+h*0.1;
    group.add(ant);
    const blink=new THREE.Mesh(new THREE.SphereGeometry(0.25,6,6),new THREE.MeshBasicMaterial({color:0xef4444}));
    blink.position.y=h+topH+h*0.2;
    blink.userData.blink=true;
    group.add(blink);
  }
  const winMat=new THREE.MeshBasicMaterial({color:palette.window,transparent:true,opacity:0.9});
  const winRows=Math.floor(h/3.5);
  const winColsX=Math.floor(w/2.5);
  const winColsZ=Math.floor(d/2.5);
  for(let face of[-1,1]){
    for(let r=1;r<winRows-1;r++){
      for(let c=0;c<winColsX;c++){
        if(Math.random()>0.35){
          const wMat=winMat.clone();
          wMat.opacity=Math.random()*0.6+0.3;
          const win=new THREE.Mesh(new THREE.BoxGeometry(0.8,1.4,0.05),wMat);
          win.position.set((c-(winColsX-1)/2)*2.2, r*3.4-h/2+1, face*(d/2+0.03));
          win.userData.isWindow=true; win.userData.baseOpacity=wMat.opacity;
          mesh.add(win); windowMeshes.push(win);
        }
      }
    }
  }
  for(let face of[-1,1]){
    for(let r=1;r<winRows-1;r++){
      for(let c=0;c<winColsZ;c++){
        if(Math.random()>0.4){
          const wMat=winMat.clone();
          wMat.opacity=Math.random()*0.6+0.3;
          const win=new THREE.Mesh(new THREE.BoxGeometry(0.05,1.4,0.8),wMat);
          win.position.set(face*(w/2+0.03), r*3.4-h/2+1, (c-(winColsZ-1)/2)*2.2);
          win.userData.isWindow=true; win.userData.baseOpacity=wMat.opacity;
          mesh.add(win); windowMeshes.push(win);
        }
      }
    }
  }
  if(h>25){
    for(let i=0;i<Math.floor(Math.random()*3+1);i++){
      const hw=Math.random()*2+1,hh=Math.random()*1.5+0.5,hd=Math.random()*2+1;
      const hMesh=new THREE.Mesh(new THREE.BoxGeometry(hw,hh,hd),new THREE.MeshLambertMaterial({color:0x334155}));
      hMesh.position.set((Math.random()-0.5)*w*0.6, h+hh/2, (Math.random()-0.5)*d*0.6);
      group.add(hMesh);
    }
    const strip=new THREE.Mesh(new THREE.BoxGeometry(w,0.15,d),new THREE.MeshBasicMaterial({color:palette.window,transparent:true,opacity:0.5}));
    strip.position.y=h+0.08;
    group.add(strip);
  }
  group.position.set(x,0,z);
  group.userData={mainMesh:mesh,mat,palette,originalY:0,portfolioIdx,isPortfolio:portfolioIdx>=0,isLandmark};
  scene.add(group);
  buildings.push(group);
  if(portfolioIdx>=0) portfolioBuildings.push(group);
  return group;
}

(function generateCity(){
  const rand=(min,max)=>min+Math.random()*(max-min);
  const portfolioPositions=[
    [-28,-28],
    [28,-28],
    [-28,28],
    [28,28],
    [-28,100],
    [28,100],
    [-56,-28],  
    [56,28],   
  ];
  portfolioData.forEach((d,i)=>{
    const [px,pz]=portfolioPositions[i];
    const p=buildingPalette[i%buildingPalette.length];
    makeBuilding(px,pz,10,45+i*5,10,p,i,true);
  });
  for(let i=0;i<300;i++){
    let x=rand(-220,240), z=rand(-220,240);
    let w=rand(6,14), d=rand(6,14);
    let h=rand(12,i<45?75:35);
    if(!checkRoadCollision(x,z,w,d)){
      makeBuilding(x,z,w,h,d,buildingPalette[Math.floor(Math.random()*buildingPalette.length)],-1,h>50);
    }
  }
})();

const cars=[];
const carGroup=new THREE.Group();
scene.add(carGroup);
function spawnCar(lane,axis){
  const colors=[0xfacc15,0xeab308,0x1e293b,0xffffff,0x3b82f6];
  const carMat=new THREE.MeshLambertMaterial({color:colors[Math.floor(Math.random()*colors.length)]});
  const car=new THREE.Mesh(new THREE.BoxGeometry(1.8,0.9,3.6),carMat);
  const headMat=new THREE.MeshBasicMaterial({color:0xfffde7});
  const headGeo=new THREE.SphereGeometry(0.18,8,8);
  for(let s of[-0.5,0.5]){
    const hl=new THREE.Mesh(headGeo,headMat);
    hl.position.set(s,-0.1,1.9);
    car.add(hl);
    const hLight=new THREE.PointLight(0xfacc15,1.2,8);
    hLight.position.copy(hl.position);
    car.add(hLight);
  }
  const tailMat=new THREE.MeshBasicMaterial({color:0xef4444});
  for(let s of[-0.5,0.5]){
    const tl=new THREE.Mesh(headGeo,tailMat);
    tl.position.set(s,-0.1,-1.9);
    car.add(tl);
  }
  const startPos=-250+Math.random()*500;
  if(axis==='z'){
    car.position.set(lane,0.6,startPos);
    car.userData={axis:'z',speed:(Math.random()>0.5?1:-1)*(0.4+Math.random()*0.5),lane};
    car.rotation.y=car.userData.speed>0?0:Math.PI;
  } else {
    car.position.set(startPos,0.6,lane);
    car.rotation.y=Math.PI/2;
    car.userData={axis:'x',speed:(Math.random()>0.5?1:-1)*(0.4+Math.random()*0.5),lane};
    if(car.userData.speed<0) car.rotation.y=-Math.PI/2;
  }
  carGroup.add(car);
  cars.push(car);
}
[-3.5,3.5,-58,62].forEach(lane=>{ for(let i=0;i<3;i++){ spawnCar(lane,'z'); spawnCar(lane,'x'); } });

const signColors=[0xfacc15,0xeab308,0x60a5fa,0x38bdf8,0xfef08a,0x2563eb];
buildings.slice(5,25).forEach((b,i)=>{
  if(Math.random()<0.4) return;
  const h=b.userData.mainMesh?.geometry?.parameters?.height||20;
  const sign=new THREE.Mesh(new THREE.BoxGeometry(5,1.5,0.2),new THREE.MeshBasicMaterial({color:signColors[i%signColors.length],transparent:true,opacity:0.85}));
  sign.position.set(b.position.x, h*0.6+b.position.y, b.position.z+(b.userData.mainMesh.geometry.parameters.depth/2+0.2));
  scene.add(sign);
  const sl=new THREE.PointLight(signColors[i%signColors.length],1.2,15);
  sl.position.copy(sign.position);
  scene.add(sl);
});

