window.addEventListener('scroll',()=>{
  const scrollTop=document.documentElement.scrollTop||document.body.scrollTop;
  const scrollSpace=document.querySelector('.scroll-space');
  const maxScroll=scrollSpace.offsetTop+scrollSpace.offsetHeight-document.documentElement.clientHeight;
  scrollPct=maxScroll>0?Math.min(1,scrollTop/maxScroll):0;
  if(isNaN(scrollPct)) scrollPct=0;
  checkPortfolioReveal();
});

function scrollToSection(pct){
  const scrollSpace=document.querySelector('.scroll-space');
  const maxScroll=scrollSpace.offsetTop+scrollSpace.offsetHeight-document.documentElement.clientHeight;
  window.scrollTo({top:pct*maxScroll,behavior:'smooth'});
}
window.scrollToSection=scrollToSection;

const altEl=document.getElementById('altitude-value');
const dots=[0,1,2,3,4].map(i=>document.getElementById('dot-'+i));
const labelEls=['intro','rooftop','midcity','street','ground'].map(l=>document.getElementById('label-'+l));

const moonToggle=document.getElementById('moon-toggle');
const dayOverlay=document.getElementById('day-overlay');
const daynightLabel=document.getElementById('daynight-label');
let transitioning=false;
moonToggle.addEventListener('click',()=>{
  if(transitioning) return;
  transitioning=true;
  isDay=!isDay;
  const dur=2500, start=performance.now();
  const dayColor=0x007acc;
  const fromFog=isDay?0x020613:dayColor, toFog=isDay?dayColor:0x020613;
  const fromBg=new THREE.Color(isDay?0x020613:dayColor), toBg=new THREE.Color(isDay?dayColor:0x020613);
  moonToggle.innerHTML = isDay ? `
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="feather feather-sun">
    <circle cx="12" cy="12" r="5"></circle>
    <line x1="12" y1="1" x2="12" y2="3"></line>
    <line x1="12" y1="21" x2="12" y2="23"></line>
    <line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line>
    <line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line>
    <line x1="1" y1="12" x2="3" y2="12"></line>
    <line x1="21" y1="12" x2="23" y2="12"></line>
    <line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line>
    <line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line>
  </svg>
` : `
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" class="feather feather-moon">
    <path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path>
  </svg>
`;
  daynightLabel.textContent=isDay?'DAY MODE':'NIGHT MODE';
  daynightLabel.style.opacity='1';
  setTimeout(()=>daynightLabel.style.opacity='0',2000);
  function tick(now){
    const t=Math.min((now-start)/dur,1);
    const ease=t<0.5?2*t*t:-1+(4-2*t)*t;
    scene.background.lerpColors(fromBg,toBg,ease);
    scene.fog.color.lerpColors(new THREE.Color(fromFog),new THREE.Color(toFog),ease);
    starMat.opacity=isDay?1-ease:ease;
    moonMesh.visible=!isDay||ease<0.5;
    sunMesh.visible=isDay;
    sunLight.intensity=isDay?ease*0.7:0;
    moonLight.intensity=isDay?0:0.5;
    dayOverlay.style.opacity=isDay?ease*0.5:0;
    windowMeshes.forEach(w=>{ w.material.opacity=isDay?w.userData.baseOpacity*(1-ease*0.7):w.userData.baseOpacity; });
    buildings.forEach(b=>{ if(b.userData.mat) b.userData.mat.emissiveIntensity=isDay?1-ease*0.8:1; });
    if(t<1) requestAnimationFrame(tick);
    else transitioning=false;
  }
  requestAnimationFrame(tick);
});

const raycaster=new THREE.Raycaster();
const mouse2d=new THREE.Vector2();
const infoPanel=document.getElementById('info-panel');
document.addEventListener('mousemove',e=>{
  mouse2d.x=(e.clientX/innerWidth)*2-1;
  mouse2d.y=-(e.clientY/innerHeight)*2+1;
  mouseX=(e.clientX/innerWidth-0.5)*2;
  mouseY=(e.clientY/innerHeight-0.5)*2;
});
function showPanel(idx){
  const d=portfolioData[idx];
  const img=document.getElementById('info-panel-img');
  const lbl=document.getElementById('info-panel-label');
  if(img) { img.src=d.image||'dummy.gif'; img.alt=d.label; }
  if(lbl) lbl.textContent=d.label;
  infoPanel.classList.add('visible');
}
document.getElementById('panel-close').addEventListener('click',()=>{
  infoPanel.classList.remove('visible');
  hoveredBuilding=null;
});

const shootingStars=[];
function spawnShootingStar(){
  const geo=new THREE.BufferGeometry();
  const pts=new Float32Array(6);
  const sx=(Math.random()-0.5)*600, sy=150+Math.random()*100, sz=-100-Math.random()*200;
  pts[0]=sx;pts[1]=sy;pts[2]=sz;pts[3]=sx+20;pts[4]=sy+5;pts[5]=sz+5;
  geo.setAttribute('position',new THREE.BufferAttribute(pts,3));
  const line=new THREE.Line(geo,new THREE.LineBasicMaterial({color:0xfef08a,transparent:true,opacity:0.8}));
  scene.add(line);
  shootingStars.push({mesh:line,vx:-1.5-Math.random()*1,vy:-0.5,vz:0.3,life:1,decay:0.015+Math.random()*0.01});
}
setInterval(()=>{ if(Math.random()<0.3) spawnShootingStar(); },3000);

function animate(){
  requestAnimationFrame(animate);
  const t=clock.getElapsedTime();
  const targetY=CAM_START.y+(CAM_END.y-CAM_START.y)*scrollPct;
  const targetZ=CAM_START.z+(CAM_END.z-CAM_START.z)*scrollPct;
  const swayX=Math.sin(t*0.3)*1.5*(1-scrollPct*0.8);
  const swayY=Math.sin(t*0.15)*0.5;
  camera.position.x+=(swayX-camera.position.x)*0.02;
  camera.position.y+=(targetY+swayY-camera.position.y)*0.04;
  camera.position.z+=(targetZ-camera.position.z)*0.04;
  camera.lookAt(mouseX*3, camera.position.y*0.3, camera.position.z-40);
  altEl.textContent=Math.round(camera.position.y)+'m';
  const secIdx=Math.min(4,Math.floor(scrollPct*5));
  dots.forEach((d,i)=>{ if(d) d.classList.toggle('active',i===secIdx); });

  const scrollProgressEl = document.getElementById('scroll-progress');
  const altitudeEl = document.getElementById('altitude');
  const infoEl = document.getElementById('info-panel');


labelEls.forEach((el, i) => {
  if (el) {
    const center = i / 4;
    const dist = Math.abs(scrollPct - center);

    if (i === 4) {

      if (scrollPct < 1.0) {
        if (scrollProgressEl) scrollProgressEl.style.opacity = 1;
        if (altitudeEl) altitudeEl.style.opacity = 1;
        
      } else {
        if (scrollProgressEl) scrollProgressEl.style.opacity = 0;
        if (altitudeEl) altitudeEl.style.opacity = 0;
        if (infoEl) infoEl.classList.remove('visible');
      }

      if (scrollPct >= 0.8 && scrollPct < 1.0) {
        el.style.opacity = 1;
      } else {
        el.style.opacity = 0;
      }

    } else {
      el.style.opacity = dist < 0.08 ? Math.max(0, (1 - dist / 0.08)) : 0;
    }
  }
});
  if(!isDay) starMat.opacity=Math.min(1,0.7+Math.sin(t)*0.15);
  cars.forEach(car=>{
    if(car.userData.axis==='z'){
      car.position.z+=car.userData.speed;
      if(Math.abs(car.position.z)>230) car.position.z=-car.position.z;
    } else {
      car.position.x+=car.userData.speed;
      if(Math.abs(car.position.x)>230) car.position.x=-car.position.x;
    }
  });
  for(let i=shootingStars.length-1;i>=0;i--){
    const s=shootingStars[i];
    const pos=s.mesh.geometry.attributes.position.array;
    pos[0]+=s.vx;pos[1]+=s.vy;pos[2]+=s.vz;
    pos[3]+=s.vx;pos[4]+=s.vy;pos[5]+=s.vz;
    s.mesh.geometry.attributes.position.needsUpdate=true;
    s.life-=s.decay; s.mesh.material.opacity=s.life;
    if(s.life<=0){ scene.remove(s.mesh); shootingStars.splice(i,1); }
  }
  if(Math.random()<0.05){
    const w=windowMeshes[Math.floor(Math.random()*windowMeshes.length)];
    if(w&&w.material){ const base=w.userData.baseOpacity||0.5; w.material.opacity=Math.random()<0.7?base:0.05; }
  }
  buildings.forEach(b=>{
    b.children.forEach(c=>{ if(c.userData.blink) c.material.color.setHex(Math.sin(t*3)>0?0xef4444:0x450a0a); });
  });
  raycaster.setFromCamera(mouse2d,camera);
  const allMeshes=buildings.map(b=>b.userData.mainMesh).filter(Boolean);
  const intersects=raycaster.intersectObjects(allMeshes);
  if(intersects.length){
    const hitMesh=intersects[0].object;
    const hitBuilding=buildings.find(b=>b.userData.mainMesh===hitMesh);
    if(hitBuilding!==hoveredBuilding){
      if(hoveredBuilding&&hoveredBuilding.userData.mat) hoveredBuilding.userData.mat.emissiveIntensity=1;
      hoveredBuilding=hitBuilding;
      if(hoveredBuilding){ hoveredBuilding.userData.mat.emissiveIntensity=3; document.body.style.cursor='pointer'; }
    }
  } else {
    if(hoveredBuilding) hoveredBuilding.userData.mat.emissiveIntensity=1;
    hoveredBuilding=null;
    document.body.style.cursor='default';
  }
  if(hoveredBuilding) hoveredBuilding.position.y+=(1.5-hoveredBuilding.position.y)*0.1;
  cloudGroup.children.forEach((c,i)=>{ c.position.x+=0.02*(i%2===0?1:-1); if(c.position.x>250)c.position.x=-250; if(c.position.x<-250)c.position.x=250; });
  pointLights.forEach((pl,i)=>{ pl.intensity=1.0+Math.sin(t*1.5+i)*0.6; });
  renderer.render(scene,camera);
}
animate();

window.addEventListener('resize',()=>{
  camera.aspect=innerWidth/innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(innerWidth,innerHeight);
});

canvas.addEventListener('click',()=>{
  raycaster.setFromCamera(mouse2d,camera);
  const hits=raycaster.intersectObjects(buildings.map(b=>b.userData.mainMesh).filter(Boolean));
  if(hits.length){
    const b=buildings.find(b=>b.userData.mainMesh===hits[0].object);
    if(b&&b.userData.isPortfolio) showPanel(b.userData.portfolioIdx);
  }
});

